final:
module top_module(
REQ,
obf_GRT
);input wire [7:0] REQ;
output reg [7:0] obf_GRT;

always@(*) begin
	obf_GRT = 8'b0000_0000;
	if (REQ[7])
		obf_GRT = 8'b1000_0000;
	else if (REQ[6])
		obf_GRT = 8'b0100_0000;
	else if (REQ[5])
		obf_GRT = 8'b0010_0000;
	else if (REQ[4])
		obf_GRT = 8'b0001_0000;
	else if (REQ[3])
		obf_GRT = 8'b0000_1000;
	else if (REQ[2])
		obf_GRT = 8'b0000_0100;
	else if (REQ[1])
		obf_GRT = 8'b0000_0010;
	else if (REQ[0])
		obf_GRT = 8'b0000_0001;
end

endmodule
